fn clean_text(text: String) -> String {
    let mut result = "".to_string();
    let mut idx = 0;
    let mut len = text.len() as i64;
    while idx < len {
        let mut ch = text.chars().nth(idx as usize).map(|c| c.to_string()).unwrap_or_default();
        if ch != " ".to_string() {
            result += ch;
        }
        idx += 1;
    }
    return result;
}

fn make_greeting(name: String, count: i64) -> String {
    return format!("Hello {}, request #{}", name, count);
}

struct TextAgent {
    pub history: String,
    pub request_count: i64,
}

impl TextAgent {
    pub fn new() -> Self {
        let mut __self = TextAgent {
            history: String::new(),
            request_count: 0,
        };
        __self.Init();
        __self
    }
    pub fn Init(&mut self) {
        self.history = "".to_string();
        self.request_count = 0;
    }
    pub fn Process(&mut self, input: String) -> String {
        self.request_count += 1;
        let mut cleaned = clean_text(input.clone());
        let mut greeting = make_greeting("User".to_string(), self.request_count.clone());
        self.history += format!("{}: {}\n", greeting, cleaned);
        return cleaned;
    }
    pub fn Run(&mut self) {
        let mut iter = 0;
        while iter < 1000 {
            let mut input = format!("  request  number  {}  ", iter);
            let mut result = self.Process(input.clone());
            iter += 1;
        }
        println!("{:?}", format!("Processed {} requests", self.request_count));
        println!("{:?}", format!("History length: {}", self.history.len() as i64));
    }
}

